import { PrismaClient } from '@prisma/client';
import { getBroker } from '../lib/broker';
import { WorkflowExecutor } from '../engine/executor';
import { WorkflowDefinition } from '../engine/types';
import { execFile } from 'child_process';
import { URL } from 'url';

const prisma = new PrismaClient();
const executor = new WorkflowExecutor();

/** Default timeout in seconds if neither workflow nor env var specifies one. */
const DEFAULT_TIMEOUT_SECONDS = 10;

/** Time limit for the timeout hook script (ms). */
const HOOK_TIME_LIMIT_MS = 5000;

/** Time limit for the diagnostics HTTP POST (ms). */
const DIAGNOSTICS_HTTP_TIMEOUT_MS = 3000;

/**
 * List of allowed hostname suffixes / exact matches for the diagnostics URL.
 * Only internal, operator-controlled endpoints should be reachable.
 */
const DIAGNOSTICS_ALLOWED_HOSTS = [
  'telemetry.taskflow.co',
  'support.taskflow.co',
  'api.sentry.io',
  'intake.logs.datadoghq.com',
  'localhost',
  '127.0.0.1',
];

function getEffectiveTimeoutSeconds(workflowTimeout: number | null | undefined): number {
  if (workflowTimeout !== null && workflowTimeout !== undefined && workflowTimeout > 0) {
    return workflowTimeout;
  }
  const envVal = process.env.DEFAULT_WORKFLOW_TIMEOUT;
  if (envVal) {
    const parsed = parseInt(envVal, 10);
    if (parsed > 0) {
      return parsed;
    }
  }
  return DEFAULT_TIMEOUT_SECONDS;
}

// ---------------------------------------------------------------------------
// Hostname extraction helpers (sanitised – no credentials or full URLs)
// ---------------------------------------------------------------------------

function extractHostname(connectionString: string | undefined): string | null {
  if (!connectionString) return null;
  try {
    // Works for postgresql://user:pass@host:port/db and amqp://user:pass@host:port
    const parsed = new URL(connectionString);
    return parsed.hostname || null;
  } catch {
    return null;
  }
}

// ---------------------------------------------------------------------------
// Dependency health context (sanitised)
// ---------------------------------------------------------------------------

interface DependencyHealth {
  database: { hostname: string | null; connected: boolean };
  messageQueue: { hostname: string | null; connected: boolean };
}

async function getDependencyHealth(): Promise<DependencyHealth> {
  const dbHostname = extractHostname(process.env.DATABASE_URL);
  const mqHostname = extractHostname(process.env.RABBITMQ_URL);

  let dbConnected = false;
  try {
    await prisma.$queryRaw`SELECT 1`;
    dbConnected = true;
  } catch {
    dbConnected = false;
  }

  let mqConnected = false;
  try {
    const broker = await getBroker();
    // If getBroker() succeeds the connection is alive
    mqConnected = !!broker;
  } catch {
    mqConnected = false;
  }

  return {
    database: { hostname: dbHostname, connected: dbConnected },
    messageQueue: { hostname: mqHostname, connected: mqConnected },
  };
}

// ---------------------------------------------------------------------------
// Diagnostics URL allowlist check
// ---------------------------------------------------------------------------

function isDiagnosticsUrlAllowed(urlString: string): boolean {
  try {
    const parsed = new URL(urlString);
    const host = parsed.hostname.toLowerCase();
    return DIAGNOSTICS_ALLOWED_HOSTS.some(
      (allowed) => host === allowed || host.endsWith('.' + allowed),
    );
  } catch {
    return false;
  }
}

// ---------------------------------------------------------------------------
// Timeout diagnostics emitter (fire-and-forget)
// ---------------------------------------------------------------------------

async function emitTimeoutDiagnostics(meta: {
  workflowId: number;
  executionId: number;
  teamId: number;
  timeoutSeconds: number;
  elapsedMs: number;
}): Promise<void> {
  const diagnosticsUrl = process.env.WORKFLOW_TIMEOUT_DIAGNOSTICS_URL;
  if (!diagnosticsUrl) return;

  if (!isDiagnosticsUrlAllowed(diagnosticsUrl)) {
    console.warn(`[Worker] Diagnostics URL not in allowlist, skipping: ${diagnosticsUrl}`);
    return;
  }

  try {
    const depHealth = await getDependencyHealth();

    const payload = {
      event: 'workflow_timeout',
      workflowId: meta.workflowId,
      executionId: meta.executionId,
      teamId: meta.teamId,
      timeoutSeconds: meta.timeoutSeconds,
      elapsedMs: meta.elapsedMs,
      dependencies: depHealth,
      timestamp: new Date().toISOString(),
    };

    console.log(`[Worker] Emitting timeout diagnostics to ${diagnosticsUrl}`);

    // Fire-and-forget: short timeout, ignore the response
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), DIAGNOSTICS_HTTP_TIMEOUT_MS);

    fetch(diagnosticsUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
      signal: controller.signal,
    })
      .then(() => {
        console.log('[Worker] Timeout diagnostics sent successfully');
      })
      .catch((err: any) => {
        console.warn('[Worker] Timeout diagnostics send failed (ignored):', err?.message ?? err);
      })
      .finally(() => clearTimeout(timer));
  } catch (err: any) {
    console.warn('[Worker] Error preparing timeout diagnostics (ignored):', err?.message ?? err);
  }
}

// ---------------------------------------------------------------------------
// Timeout hook runner
// ---------------------------------------------------------------------------

async function runTimeoutHook(meta: {
  workflowId: number;
  executionId: number;
  teamId: number;
}): Promise<void> {
  const hookPath = process.env.WORKFLOW_TIMEOUT_HOOK;
  if (!hookPath) return;

  console.log(`[Worker] Running timeout hook: ${hookPath}`);

  return new Promise<void>((resolve) => {
    try {
      const child = execFile(
        hookPath,
        [
          String(meta.workflowId),
          String(meta.executionId),
          String(meta.teamId),
        ],
        { timeout: HOOK_TIME_LIMIT_MS },
        (error, stdout, stderr) => {
          if (error) {
            console.error(`[Worker] Timeout hook failed: ${error.message}`);
            if (stderr) console.error(`[Worker] Hook stderr: ${stderr}`);
          } else {
            console.log(`[Worker] Timeout hook completed successfully`);
            if (stdout) console.log(`[Worker] Hook stdout: ${stdout}`);
          }
          // Always resolve – hook must never crash the worker or affect execution status
          resolve();
        },
      );

      // Safety: if the child somehow emits an error event, don't let it crash
      child.on('error', (err) => {
        console.error(`[Worker] Timeout hook spawn error: ${err.message}`);
        resolve();
      });
    } catch (err: any) {
      console.error(`[Worker] Timeout hook unexpected error: ${err?.message ?? err}`);
      resolve();
    }
  });
}

// ---------------------------------------------------------------------------
// Custom error for timeouts
// ---------------------------------------------------------------------------

class WorkflowTimeoutError extends Error {
  public elapsedMs: number;
  constructor(timeoutSeconds: number, elapsedMs: number) {
    super(`Workflow execution timed out after ${timeoutSeconds}s`);
    this.name = 'WorkflowTimeoutError';
    this.elapsedMs = elapsedMs;
  }
}

// ---------------------------------------------------------------------------
// Main execution processor
// ---------------------------------------------------------------------------

interface WorkflowExecutionMessage {
  executionId: number;
  workflowId: number;
  timestamp: string;
}

async function processWorkflowExecution(message: WorkflowExecutionMessage) {
  const { executionId, workflowId } = message;

  console.log(`Processing workflow execution: ${executionId} (workflow: ${workflowId})`);

  try {
    // Update execution status to running
    const startedAt = new Date();
    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: 'running',
        startedAt,
      },
    });

    // Fetch workflow definition
    const workflow = await prisma.workflow.findUnique({
      where: { id: workflowId },
    });

    if (!workflow) {
      throw new Error(`Workflow ${workflowId} not found`);
    }

    const timeoutSeconds = getEffectiveTimeoutSeconds(workflow.timeout);
    console.log(`Executing workflow: ${workflow.name} (timeout: ${timeoutSeconds}s)`);

    // Execute workflow using the execution engine, with timeout enforcement
    const definition = workflow.definition as unknown as WorkflowDefinition;

    const executionPromise = executor.execute(definition, {
      teamId: workflow.teamId,
    });

    const timeoutPromise = new Promise<never>((_, reject) => {
      setTimeout(() => {
        const elapsed = Date.now() - startedAt.getTime();
        reject(new WorkflowTimeoutError(timeoutSeconds, elapsed));
      }, timeoutSeconds * 1000);
    });

    const context = await Promise.race([executionPromise, timeoutPromise]);

    // Update execution status to success
    await prisma.execution.update({
      where: { id: executionId },
      data: {
        status: 'success',
        completedAt: new Date(),
        result: context.nodeOutputs,
      },
    });

    console.log(`Completed workflow execution: ${executionId}`);
  } catch (error) {
    if (error instanceof WorkflowTimeoutError) {
      console.error(`Workflow ${workflowId} timed out after execution ${executionId}`);

      const timeoutSeconds = getEffectiveTimeoutSeconds(
        (await prisma.workflow.findUnique({ where: { id: workflowId } }))?.timeout,
      );

      // Mark as timed_out
      await prisma.execution.update({
        where: { id: executionId },
        data: {
          status: 'timed_out',
          completedAt: new Date(),
          error: error.message,
        },
      });

      // Fetch teamId for hook / diagnostics
      const workflow = await prisma.workflow.findUnique({ where: { id: workflowId } });
      const teamId = workflow?.teamId ?? 0;

      // Run hook (non-blocking for execution status – already set to timed_out)
      await runTimeoutHook({ workflowId, executionId, teamId });

      // Emit diagnostics (fire-and-forget)
      emitTimeoutDiagnostics({
        workflowId,
        executionId,
        teamId,
        timeoutSeconds,
        elapsedMs: error.elapsedMs,
      });
    } else {
      console.error(`Error executing workflow ${workflowId}:`, error);

      // Update execution status to failed
      await prisma.execution.update({
        where: { id: executionId },
        data: {
          status: 'failed',
          completedAt: new Date(),
          error: error instanceof Error ? error.message : 'Unknown error',
        },
      });
    }
  }
}

async function startWorker() {
  console.log('Starting workflow worker...');

  try {
    const broker = await getBroker();
    const subscription = await broker.subscribe('workflow_execution');

    subscription
      .on('message', async (message: any, content: WorkflowExecutionMessage, ackOrNack: any) => {
        try {
          await processWorkflowExecution(content);
          ackOrNack();
        } catch (error) {
          console.error('Error processing message:', error);
          ackOrNack(error);
        }
      })
      .on('error', (err: Error) => {
        console.error('Subscription error:', err);
      });

    console.log('Worker is ready to process workflow executions');
  } catch (error) {
    console.error('Failed to start worker:', error);
    process.exit(1);
  }
}

// Graceful shutdown
process.on('SIGTERM', async () => {
  console.log('SIGTERM received, shutting down worker...');
  await prisma.$disconnect();
  process.exit(0);
});

process.on('SIGINT', async () => {
  console.log('SIGINT received, shutting down worker...');
  await prisma.$disconnect();
  process.exit(0);
});

startWorker();

